  1	import * as React from 'react';
  2	import { CREATE_SS_PAGE_URL } from '@odf/core/constants';
  3	import { StartingPoint } from '@odf/core/types/install-ui';
  4	import { useCustomTranslation } from '@odf/shared';
  5	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
  6	import { useNavigate } from 'react-router-dom-v5-compat';
  7	import {
  8	  Flex,
  9	  FlexItem,
 10	  Card,
 11	  CardHeader,
 12	  CardTitle,
 13	  CardBody,
 14	  TextContent,
 15	  Text,
 16	  Modal,
 17	  Title,
 18	  Button,
 19	} from '@patternfly/react-core';
 20	import { ExternalSystemsSelectModal } from './ExternalSystemsModal';
 21	import './StorageClusterCreateModal.scss';
 22	
 23	type ConfigureDFSelectionsProps = {
 24	  closeModal: () => void;
 25	};
 26	
 27	export const ConfigureDFSelections: React.FC<ConfigureDFSelectionsProps> = ({
 28	  closeModal,
 29	}) => {
 30	  const { t } = useCustomTranslation();
 31	  const navigate = useNavigate();
 32	  const launchModal = useModal();
 33	
 34	  const redirectTo = (installationFlow: StartingPoint) => () => {
 35	    const urlParams = new URLSearchParams({ mode: installationFlow });
 36	    navigate(`${CREATE_SS_PAGE_URL}?${urlParams.toString()}`);
 37	    closeModal();
 38	  };
 39	
 40	  const showExternalSystems = () => {
 41	    closeModal();
 42	    launchModal(ExternalSystemsSelectModal, {});
 43	  };
 44	
 45	  return (
 46	    <Flex
 47	      direction={{ default: 'row' }}
 48	      spaceItems={{ default: 'spaceItemsXl', md: 'spaceItemsMd' }}
 49	      className="odf-storage-cluster-create-modal__cards-container"
 50	    >
 51	      <FlexItem>
 52	        <Card
 53	          id="setup-storage-cluster"
 54	          isClickable
 55	          className="odf-storage-cluster-create-modal__setup-card"
 56	          data-test="create-storage-cluster"
 57	        >
 58	          <CardHeader
 59	            selectableActions={{
 60	              onClickAction: redirectTo(StartingPoint.STORAGE_CLUSTER),
 61	              selectableActionId: StartingPoint.STORAGE_CLUSTER,
 62	            }}
 63	          >
 64	            <CardTitle>{t('Create Storage Cluster')}</CardTitle>
 65	          </CardHeader>
 66	          <CardBody>
 67	            <TextContent>
 68	              <Text component="small">
 69	                {t(
 70	                  'Provision a storage cluster using local devices on your OpenShift nodes.'
 71	                )}
 72	              </Text>
 73	            </TextContent>
 74	          </CardBody>
 75	        </Card>
 76	      </FlexItem>
 77	      <FlexItem>
 78	        <Card
 79	          isClickable
 80	          id="connect-external-system"
 81	          className="odf-storage-cluster-create-modal__setup-card"
 82	        >
 83	          <CardHeader
 84	            selectableActions={{
 85	              onClickAction: showExternalSystems,
 86	              selectableActionId: 'external-system',
 87	            }}
 88	          >
 89	            <CardTitle>{t('Connect to an external system')}</CardTitle>
 90	          </CardHeader>
 91	          <CardBody>
 92	            <TextContent>
 93	              <Text component="small">
 94	                {t(
 95	                  'Integrate Data Foundation with an existing storage backend such as external Ceph cluster or IBM FlashSystem.'
 96	                )}
 97	              </Text>
 98	            </TextContent>
 99	          </CardBody>
100	        </Card>
101	      </FlexItem>
102	      <FlexItem>
103	        <Card
104	          id="setup-object-storage"
105	          className="odf-storage-cluster-create-modal__setup-card"
106	          isClickable
107	        >
108	          <CardHeader
109	            selectableActions={{
110	              onClickAction: redirectTo(StartingPoint.OBJECT_STORAGE),
111	              selectableActionId: StartingPoint.OBJECT_STORAGE,
112	            }}
113	          >
114	            <CardTitle>{t('Setup Multicloud Object Gateway')}</CardTitle>
115	          </CardHeader>
116	          <CardBody>
117	            <TextContent>
118	              <Text component="small">
119	                {t(
120	                  'Enable S3-compatible object storage that spans across multiple cloud providers or hybrid environments'
121	                )}
122	              </Text>
123	            </TextContent>
124	          </CardBody>
125	        </Card>
126	      </FlexItem>
127	    </Flex>
128	  );
129	};
130	
131	const ModalHeader: React.FC = () => {
132	  const { t } = useCustomTranslation();
133	  return (
134	    <>
135	      <Title headingLevel="h1" id="welcome-df-modal-title">
136	        {t('Welcome to Data Foundation')}
137	      </Title>
138	      <TextContent>
139	        <Text component="small">
140	          {t(
141	            'Data Foundation simplifies persistent storage and data services across your infrastructure.'
142	          )}
143	        </Text>
144	      </TextContent>
145	    </>
146	  );
147	};
