150	  closeModal: () => void;
151	};
152	
153	export const StorageClusterCreateModal: React.FC<
154	  DataFoundationInitialCreateModalProps
155	> = ({ closeModal }) => {
156	  const { t } = useCustomTranslation();
157	
158	  return (
159	    <Modal
160	      aria-label="Welcome to Data Foundation"
161	      width="auto"
162	      isOpen={true}
163	      title={t('Welcome to Data Foundation')}
164	      header={<ModalHeader />}
165	      onClose={closeModal}
166	      className="odf-storage-cluster-create-modal"
167	      actions={[
168	        <Button
169	          key="create-storage-cluster"
170	          variant="link"
171	          onClick={closeModal}
172	        >
173	          {t('Cancel')}
174	        </Button>,
175	      ]}
176	    >
177	      <TextContent className="odf-storage-cluster-create-modal__body-text">
178	        <Text component="h4">
179	          {t('Choose how to set your Data Foundation cluster')}
180	        </Text>
181	        <Text component="small">
182	          {t(
183	            'This selection determines the storage capabilities of your cluster. Once configured it cannot be changed.'
184	          )}
185	        </Text>
186	      </TextContent>
187	      <ConfigureDFSelections closeModal={closeModal} />
188	    </Modal>
189	  );
190	};

