  1	import * as React from 'react';
  2	import { CREATE_SS_PAGE_URL } from '@odf/core/constants';
  3	import { render, screen } from '@testing-library/react';
  4	import userEvent from '@testing-library/user-event';
  5	import '@testing-library/jest-dom';
  6	import {
  7	  ConfigureDFSelections,
  8	  StorageClusterCreateModal,
  9	} from './StorageClusterCreateModal';
 10	
 11	// Mock react-router-dom-v5-compat
 12	const mockNavigate = jest.fn();
 13	jest.mock('react-router-dom-v5-compat', () => ({
 14	  ...jest.requireActual('react-router-dom-v5-compat'),
 15	  useNavigate: () => mockNavigate,
 16	}));
 17	
 18	// Mock useCustomTranslation
 19	jest.mock('@odf/shared', () => ({
 20	  ...jest.requireActual('@odf/shared'),
 21	  useCustomTranslation: () => ({
 22	    t: (key: string) => key,
 23	  }),
 24	}));
 25	
 26	// Mock console.log to verify redirect logging
 27	const mockConsoleLog = jest.spyOn(console, 'log').mockImplementation(jest.fn());
 28	
 29	describe('ConfigureDFSelections', () => {
 30	  const mockCloseModal = jest.fn();
 31	
 32	  beforeEach(() => {
 33	    jest.clearAllMocks();
 34	  });
 35	
 36	  afterAll(() => {
 37	    mockConsoleLog.mockRestore();
 38	  });
 39	
 40	  it('should render all three storage setup cards', () => {
 41	    render(<ConfigureDFSelections closeModal={mockCloseModal} />);
 42	
 43	    expect(screen.getByText('Create Storage Cluster')).toBeInTheDocument();
 44	    expect(
 45	      screen.getByText('Connect to an external system')
 46	    ).toBeInTheDocument();
 47	    expect(
 48	      screen.getByText('Setup Multicloud Object Gateway')
 49	    ).toBeInTheDocument();
 50	  });
 51	
 52	  it('should render card descriptions', () => {
 53	    render(<ConfigureDFSelections closeModal={mockCloseModal} />);
 54	
 55	    expect(
 56	      screen.getByText(
 57	        'Provision a storage cluster using local devices on your OpenShift nodes.'
 58	      )
 59	    ).toBeInTheDocument();
 60	    expect(
 61	      screen.getByText(
 62	        'Integrate Data Foundation with an existing storage backend such as external Ceph cluster or IBM FlashSystem.'
 63	      )
 64	    ).toBeInTheDocument();
 65	    expect(
 66	      screen.getByText(
 67	        'Enable S3-compatible object storage that spans across multiple cloud providers or hybrid environments'
 68	      )
 69	    ).toBeInTheDocument();
 70	  });
 71	
 72	  it('should navigate to storage cluster creation when storage cluster card is clicked', async () => {
 73	    const user = userEvent.setup();
 74	    const { container } = render(
 75	      <ConfigureDFSelections closeModal={mockCloseModal} />
 76	    );
 77	
 78	    const storageClusterCard = container.querySelector(
 79	      '#storage-cluster'
 80	    ) as Element;
 81	    await user.click(storageClusterCard);
 82	
 83	    expect(mockNavigate).toHaveBeenCalledWith(
 84	      `${CREATE_SS_PAGE_URL}?mode=storage-cluster`
 85	    );
 86	    expect(mockCloseModal).toHaveBeenCalled();
 87	  });
 88	
 89	  it('should navigate to external system creation when external system card is clicked', async () => {
 90	    const user = userEvent.setup();
 91	    const { container } = render(
 92	      <ConfigureDFSelections closeModal={mockCloseModal} />
 93	    );
 94	
 95	    const externalSystemCard = container.querySelector(
 96	      '#external-system'
 97	    ) as Element;
 98	    await user.click(externalSystemCard);
 99	
100	    expect(mockCloseModal).toHaveBeenCalled();
101	  });
102	
103	  it('should navigate to MCG setup when MCG card is clicked', async () => {
104	    const user = userEvent.setup();
105	    const { container } = render(
106	      <ConfigureDFSelections closeModal={mockCloseModal} />
107	    );
108	
109	    const mcgCard = container.querySelector('#object-storage') as Element;
110	    await user.click(mcgCard);
111	
112	    expect(mockNavigate).toHaveBeenCalledWith(
113	      `${CREATE_SS_PAGE_URL}?mode=object-storage`
114	    );
115	    expect(mockCloseModal).toHaveBeenCalled();
116	  });
117	
118	  it('should have correct card IDs', () => {
119	    render(<ConfigureDFSelections closeModal={mockCloseModal} />);
120	
121	    expect(
122	      screen.getByText('Create Storage Cluster').closest('.pf-v6-c-card')
123	    ).toHaveAttribute('id', 'setup-storage-cluster');
124	    expect(
125	      screen.getByText('Connect to an external system').closest('.pf-v6-c-card')
126	    ).toHaveAttribute('id', 'connect-external-system');
127	    expect(
128	      screen
129	        .getByText('Setup Multicloud Object Gateway')
130	        .closest('.pf-v6-c-card')
131	    ).toHaveAttribute('id', 'setup-object-storage');
132	  });
133	
134	  it('should have clickable cards', () => {
135	    render(<ConfigureDFSelections closeModal={mockCloseModal} />);
136	
137	    const storageClusterCard = screen
138	      .getByText('Create Storage Cluster')
139	      .closest('.pf-v6-c-card');
140	    const externalSystemCard = screen
141	      .getByText('Connect to an external system')
142	      .closest('.pf-v6-c-card');
143	    const mcgCard = screen
144	      .getByText('Setup Multicloud Object Gateway')
145	      .closest('.pf-v6-c-card');
146	
147	    expect(storageClusterCard).toHaveClass('pf-m-clickable');
148	    expect(externalSystemCard).toHaveClass('pf-m-clickable');
149	    expect(mcgCard).toHaveClass('pf-m-clickable');
150	  });
151	});
