153	describe('StorageClusterCreateModal', () => {
154	  const mockCloseModal = jest.fn();
155	
156	  beforeEach(() => {
157	    jest.clearAllMocks();
158	  });
159	
160	  it('should render the modal with correct title', () => {
161	    render(<StorageClusterCreateModal closeModal={mockCloseModal} />);
162	
163	    expect(screen.getByText('Welcome to Data Foundation')).toBeInTheDocument();
164	    expect(
165	      screen.getByRole('heading', { name: 'Welcome to Data Foundation' })
166	    ).toBeInTheDocument();
167	  });
168	
169	  it('should render the modal description', () => {
170	    render(<StorageClusterCreateModal closeModal={mockCloseModal} />);
171	
172	    expect(
173	      screen.getByText(
174	        'Data Foundation simplifies persistent storage and data services across your infrastructure.'
175	      )
176	    ).toBeInTheDocument();
177	  });
178	
179	  it('should render the setup instruction text', () => {
180	    render(<StorageClusterCreateModal closeModal={mockCloseModal} />);
181	
182	    expect(
183	      screen.getByText('Choose how to set your Data Foundation cluster')
184	    ).toBeInTheDocument();
185	    expect(
186	      screen.getByText(
187	        'This selection determines the storage capabilities of your cluster. Once configured it cannot be changed.'
188	      )
189	    ).toBeInTheDocument();
190	  });
191	
192	  it('should render the cancel button', () => {
193	    render(<StorageClusterCreateModal closeModal={mockCloseModal} />);
194	
195	    expect(screen.getByRole('button', { name: 'Cancel' })).toBeInTheDocument();
196	  });
197	
198	  it('should call closeModal when cancel button is clicked', async () => {
199	    const user = userEvent.setup();
200	    render(<StorageClusterCreateModal closeModal={mockCloseModal} />);
201	
202	    const cancelButton = screen.getByRole('button', { name: 'Cancel' });
203	    await user.click(cancelButton);
204	
205	    expect(mockCloseModal).toHaveBeenCalledTimes(1);
206	  });
207	
208	  it('should call closeModal when modal is closed via onClose', async () => {
209	    const user = userEvent.setup();
210	    render(<StorageClusterCreateModal closeModal={mockCloseModal} />);
211	
212	    // Simulate modal close event
213	    await user.keyboard('{Escape}');
214	
215	    expect(mockCloseModal).toHaveBeenCalled();
216	  });
217	
218	  it('should render all ConfigureDFSelections cards within the modal', () => {
219	    render(<StorageClusterCreateModal closeModal={mockCloseModal} />);
220	
221	    expect(screen.getByText('Create Storage Cluster')).toBeInTheDocument();
222	    expect(
223	      screen.getByText('Connect to an external system')
224	    ).toBeInTheDocument();
225	    expect(
226	      screen.getByText('Setup Multicloud Object Gateway')
227	    ).toBeInTheDocument();
228	  });
229	
230	  it('should have modal open by default', () => {
231	    render(<StorageClusterCreateModal closeModal={mockCloseModal} />);
232	
233	    const modal = screen.getByRole('dialog');
234	    expect(modal).toBeInTheDocument();
235	  });
236	
237	  it('should have correct modal width', () => {
238	    render(<StorageClusterCreateModal closeModal={mockCloseModal} />);
239	
240	    const modal = screen.getByRole('dialog');
241	    expect(modal).toHaveStyle('--pf-v6-c-modal-box--Width: auto');
242	  });
243	
244	  it('should have correct modal title ID', () => {
245	    render(<StorageClusterCreateModal closeModal={mockCloseModal} />);
246	
247	    expect(
248	      screen.getByRole('heading', { name: 'Welcome to Data Foundation' })
249	    ).toHaveAttribute('id', 'welcome-df-modal-title');
250	  });
251	});
