254	  const mockCloseModal = jest.fn();
255	
256	  beforeEach(() => {
257	    jest.clearAllMocks();
258	  });
259	
260	  it('should navigate and close modal when a card is clicked within the modal', async () => {
261	    const user = userEvent.setup();
262	    render(<StorageClusterCreateModal closeModal={mockCloseModal} />);
263	
264	    const storageClusterCard = document.body.querySelector(
265	      '#storage-cluster'
266	    ) as Element;
267	    expect(storageClusterCard).not.toBeNull();
268	    await user.click(storageClusterCard);
269	
270	    /* expect(mockNavigate).toHaveBeenCalledWith(
