272	    );
273	    expect(mockCloseModal).toHaveBeenCalledTimes(1); */
274	  });
275	
276	  it('should handle multiple card clicks correctly', async () => {
277	    const user = userEvent.setup();
278	    render(<StorageClusterCreateModal closeModal={mockCloseModal} />);
279	
280	    // Click MCG card
281	    const mcgCard = document.body.querySelector('#object-storage') as Element;
282	    await user.click(mcgCard);
283	
284	    expect(mockNavigate).toHaveBeenCalledWith(
285	      `${CREATE_SS_PAGE_URL}?mode=object-storage`
286	    );
